const config=require("./config");async function testCollectionVolume(identifier,collectionName,isSlug=!1){console.log(`🧪 Testing ${collectionName} collection volume...`),console.log(`📍 ${isSlug?"Slug":"Contract"}: ${identifier}`);try{const apiKey=config.opensea.apiKey;console.log("🔍 Trying OpenSea API v2...");const v2Response=await fetch(`https://api.opensea.io/api/v2/collections/${identifier}`,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(v2Response.ok){const v2Data=await v2Response.json();console.log(`✅ ${collectionName} v2 data found!`),console.log(`📝 Name: ${v2Data.name||"N/A"}`),console.log(`🔗 Slug: ${v2Data.slug||"N/A"}`),console.log("🐦 Twitter: "+(v2Data.twitter_username?`@${v2Data.twitter_username}`:"N/A")),console.log(`💬 Discord: ${v2Data.discord_url||"N/A"}`),console.log(`🌐 External URL: ${v2Data.external_url||"N/A"}`),console.log(`🔗 OpenSea URL: ${v2Data.opensea_url||"N/A"}`),console.log(`🌐 Project URL: ${v2Data.project_url||"N/A"}`),console.log(`📸 Image URL: ${v2Data.image_url||"N/A"}`),console.log("📄 Description: "+(v2Data.description?v2Data.description.substring(0,100)+"...":"N/A"));const statsEndpoints=[`https://api.opensea.io/api/v2/collections/${identifier}/stats`,`https://api.opensea.io/api/v2/collections/${identifier}/stats?chain=ethereum`,`https://api.opensea.io/api/v2/collections/${identifier}/stats?chain=ethereum&format=json`];for(let i=0;i<statsEndpoints.length;i++){const endpoint=statsEndpoints[i];console.log(`🔍 Trying v2 stats endpoint ${i+1}: ${endpoint}`);const v2StatsResponse=await fetch(endpoint,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(v2StatsResponse.ok){const v2StatsData=await v2StatsResponse.json();console.log(`✅ ${collectionName} v2 stats found with endpoint ${i+1}!`),console.log("📊 Raw stats data:",JSON.stringify(v2StatsData,null,2)),console.log(`💰 Floor Price: ${v2StatsData.stats?.floor_price||"N/A"} ETH`),console.log(`📊 Total Volume: $${v2StatsData.stats?.total_volume?.toLocaleString()||"N/A"}`),console.log(`📊 24h Volume: $${v2StatsData.stats?.one_day_volume?.toLocaleString()||"N/A"}`),console.log(`📊 7d Volume: $${v2StatsData.stats?.seven_day_volume?.toLocaleString()||"N/A"}`),console.log("📈 24h Change: "+(v2StatsData.stats?.floor_price_change_24h?(100*v2StatsData.stats.floor_price_change_24h).toFixed(2)+"%":"N/A")),console.log("📈 7d Change: "+(v2StatsData.stats?.floor_price_change_7d?(100*v2StatsData.stats.floor_price_change_7d).toFixed(2)+"%":"N/A"));break}console.log(`❌ v2 stats endpoint ${i+1} failed: ${v2StatsResponse.status} ${v2StatsResponse.statusText}`)}return}console.log(`❌ v2 API failed: ${v2Response.status} ${v2Response.statusText}`),console.log("🔍 Trying OpenSea API v1 without chain...");const v1Response=await fetch(`https://api.opensea.io/api/v1/collection/${identifier}`,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(v1Response.ok){const v1Data=await v1Response.json();if(console.log(`✅ ${collectionName} v1 data found!`),v1Data.collection){const collection=v1Data.collection;console.log(`📝 Name: ${collection.name||"N/A"}`),console.log(`🔗 Slug: ${collection.slug||"N/A"}`),console.log("🐦 Twitter: "+(collection.twitter_username?`@${collection.twitter_username}`:"N/A")),console.log(`💬 Discord: ${collection.discord_url||"N/A"}`)}const statsResponse=await fetch(`https://api.opensea.io/api/v1/collection/${identifier}/stats`,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(statsResponse.ok){const statsData=await statsResponse.json();if(statsData.stats){const stats=statsData.stats;console.log(`💰 Total Volume: $${stats.total_volume?.toLocaleString()||"N/A"}`),console.log(`🎯 Floor Price: ${stats.floor_price||"N/A"} ETH`),console.log(`📊 24h Volume: $${stats.one_day_volume?.toLocaleString()||"N/A"}`),console.log(`📊 7d Volume: $${stats.seven_day_volume?.toLocaleString()||"N/A"}`),console.log("📈 24h Change: "+(stats.floor_price_change_24h?(100*stats.floor_price_change_24h).toFixed(2)+"%":"N/A")),console.log("📈 7d Change: "+(stats.floor_price_change_7d?(100*stats.floor_price_change_7d).toFixed(2)+"%":"N/A"))}}else console.log(`❌ Stats API failed: ${statsResponse.status} ${statsResponse.statusText}`)}else console.log(`❌ v1 API failed: ${v1Response.status} ${v1Response.statusText}`)}catch(error){console.error(`❌ Error with ${collectionName}:`,error.message)}console.log("─".repeat(50))}async function testCoolCatsVolume(){console.log("🧪 Testing Cool Cats collection volume...\n"),console.log("🔍 Testing Cool Cats...\n");const coolCatsIdentifiers=["cool-cats-nft","coolcats","cool-cats","0x1A92f7381B9F03921564a437210bB9396471050C"];for(const identifier of coolCatsIdentifiers)await testCollectionVolume(identifier,"Cool Cats",!identifier.startsWith("0x"));console.log("\n🧪 Testing BAYC as control...\n"),await testCollectionVolume("boredapeyachtclub","BAYC",!0),console.log("\n🧪 Testing Doodles...\n"),await testCollectionVolume("doodles-official","Doodles",!0),console.log("\n🧪 Testing Azuki...\n"),await testCollectionVolume("azuki","Azuki",!0)}testCoolCatsVolume();